import { useEffect, useState } from "react";

const CHARSETS = {
  standard: " .'~^,:;Il!i><+_-?][}{1)(|/tfjrxnuvczXYUJCLQ0OZmwqpdbkhao*#MW&8%B@$",
  blocks: " ░▒▓█",
  minimal: " .-:=+*#%@",
};

const IMG_SRC = "data:image/png;base64,";

function imageToAsciiData(img, cols, charsetName) {
  const chars = CHARSETS[charsetName] || CHARSETS.standard;
  const canvas = document.createElement("canvas");
  const ctx = canvas.getContext("2d");
  const aspect = img.naturalHeight / img.naturalWidth;
  const rows = Math.floor(cols * aspect * 0.5);
  canvas.width = cols;
  canvas.height = rows;
  ctx.drawImage(img, 0, 0, cols, rows);
  const { data } = ctx.getImageData(0, 0, cols, rows);
  const result = [];
  for (let y = 0; y < rows; y++) {
    const row = [];
    for (let x = 0; x < cols; x++) {
      const i = (y * cols + x) * 4;
      const r = data[i], g = data[i + 1], b = data[i + 2];
      const lum = (0.299 * r + 0.587 * g + 0.114 * b) / 255;
      const ci = Math.floor(lum * (chars.length - 1));
      const mx = Math.max(r, g, b), mn = Math.min(r, g, b);
      const sat = mx > 0 ? (mx - mn) / mx : 0;
      const boost = sat > 0.1 ? 1.3 : 1;
      row.push({
        char: chars[ci],
        r: Math.min(255, Math.floor(r * boost)),
        g: Math.min(255, Math.floor(g * boost)),
        b: Math.min(255, Math.floor(b * boost)),
        lum,
      });
    }
    result.push(row);
  }
  return result;
}

export default function AsciiMountains() {
  const [asciiData, setAsciiData] = useState(null);
  const [cols, setCols] = useState(140);
  const [fontSize, setFontSize] = useState(5);
  const [charset, setCharset] = useState("standard");
  const [colorMode, setColorMode] = useState("color");

  useEffect(() => {
    const img = new Image();
    img.onload = () => setAsciiData(imageToAsciiData(img, cols, charset));
    img.src = IMG_SRC;
  }, [cols, charset]);

  const getColor = (c) => {
    if (colorMode === "mono") {
      const r = Math.floor(50 + c.lum * 200);
      const g = Math.floor(30 + c.lum * 185);
      const b = Math.floor(100 + c.lum * 155);
      return `rgb(${r},${g},${b})`;
    }
    if (colorMode === "matrix") {
      return `rgb(0,${Math.floor(40 + c.lum * 215)},0)`;
    }
    return `rgb(${c.r},${c.g},${c.b})`;
  };

  const Pill = ({ label, active, onClick }) => (
    <button
      onClick={onClick}
      style={{
        padding: "4px 10px",
        fontSize: 10,
        fontFamily: "monospace",
        textTransform: "uppercase",
        letterSpacing: "0.8px",
        border: active ? "1px solid rgba(200,180,255,0.45)" : "1px solid rgba(255,255,255,0.08)",
        borderRadius: 4,
        background: active ? "rgba(200,180,255,0.1)" : "transparent",
        color: active ? "#ddd0ff" : "#666",
        cursor: "pointer",
        transition: "all 0.15s",
      }}
    >
      {label}
    </button>
  );

  return (
    <div style={{ minHeight: "100vh", background: "#08060e", display: "flex", flexDirection: "column", alignItems: "center", fontFamily: "monospace" }}>
      {/* Controls */}
      <div style={{ width: "100%", padding: "14px 24px", display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap", borderBottom: "1px solid rgba(255,255,255,0.04)" }}>
        <div style={{ display: "flex", gap: 4 }}>
          {["color", "mono", "matrix"].map((m) => (
            <Pill key={m} label={m} active={colorMode === m} onClick={() => setColorMode(m)} />
          ))}
        </div>
        <div style={{ display: "flex", gap: 4, borderLeft: "1px solid rgba(255,255,255,0.06)", paddingLeft: 14 }}>
          {Object.keys(CHARSETS).map((c) => (
            <Pill key={c} label={c} active={charset === c} onClick={() => setCharset(c)} />
          ))}
        </div>
        <div style={{ display: "flex", gap: 14, marginLeft: "auto", alignItems: "center" }}>
          <label style={{ display: "flex", alignItems: "center", gap: 6, color: "#555", fontSize: 10, textTransform: "uppercase", letterSpacing: 1 }}>
            Cols
            <input type="range" min={60} max={200} step={10} value={cols} onChange={(e) => setCols(+e.target.value)} style={{ width: 70, accentColor: "#7b5ea7" }} />
            <span style={{ color: "#777", minWidth: 22 }}>{cols}</span>
          </label>
          <label style={{ display: "flex", alignItems: "center", gap: 6, color: "#555", fontSize: 10, textTransform: "uppercase", letterSpacing: 1 }}>
            Size
            <input type="range" min={2} max={12} step={0.5} value={fontSize} onChange={(e) => setFontSize(+e.target.value)} style={{ width: 70, accentColor: "#7b5ea7" }} />
            <span style={{ color: "#777", minWidth: 22 }}>{fontSize}</span>
          </label>
        </div>
      </div>

      {/* ASCII output */}
      <div style={{ flex: 1, display: "flex", alignItems: "center", justifyContent: "center", padding: 20, overflow: "auto", width: "100%" }}>
        {!asciiData ? (
          <div style={{ color: "#444", fontSize: 12 }}>Loading...</div>
        ) : (
          <pre style={{ lineHeight: 1.05, fontSize, letterSpacing: "0.3px", fontFamily: "'JetBrains Mono','Fira Code','Courier New',monospace", margin: 0, background: "transparent" }}>
            {asciiData.map((row, y) => (
              <div key={y} style={{ height: fontSize * 1.05 }}>
                {row.map((cell, x) =>
                  cell.lum < 0.015 ? " " : (
                    <span key={x} style={{ color: getColor(cell) }}>
                      {cell.char === "<" ? "\u003c" : cell.char === ">" ? "\u003e" : cell.char}
                    </span>
                  )
                )}
              </div>
            ))}
          </pre>
        )}
      </div>
    </div>
  );
}